const body=$input.first().json.body||$input.first().json;
const db06_id=(body.db06_id||body.id||'').toString().replace(/-/g,'');
if(!db06_id) throw new Error('missing db06_id');
return [{ json:{ db06_id } }];

const p=$input.first().json;
const T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"];
let target_id='',target_rel='';
for(const r of T){const a=p.properties[r]?.relation||[]; if(a.length){target_id=(a[0].id||'').replace(/-/g,'');target_rel=r;break;}}
return [{ json:{
  db06_id:p.id.replace(/-/g,''),
  ai_mode:p.properties['ai模式']?.select?.name||'聯想',
  exec_idea:p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('')||'',
  db05_id:target_id, target_rel,
  sort_num:p.properties['排序']?.number
}}];

const baton = $('Parse DB06').first().json;
const target = $('Fetch target').first().json;
const NHEAD = {'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const norm = id => (id||'').replace(/-/g,'');
const withTO = (p,ms) => Promise.race([p, new Promise((_,rej)=>setTimeout(()=>rej(new Error('to')),ms))]);
const getPage = async id => { try { const r = await withTO(this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/pages/'+id,headers:NHEAD}), 10000); return (typeof r==='string')?JSON.parse(r):r; } catch(e){ return null; } };
const getDB = async id => { try { const r = await withTO(this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/databases/'+id,headers:NHEAD}), 10000); return (typeof r==='string')?JSON.parse(r):r; } catch(e){ return null; } };
const titleOf = p => { const tp = Object.values(p.properties||{}).find(v=>v&&v.type==='title'); return (tp?.title||[]).map(t=>t.plain_text).join(''); };
const rtOf = (p,k) => ((p.properties||{})[k]?.rich_text||[]).map(t=>t.plain_text).join('');
const relIdsOf = (p,k) => (((p.properties||{})[k]?.relation)||[]).map(r=>norm(r.id));
const duiYingRels = p => { const out=[]; for(const [k,v] of Object.entries(p.properties||{})){ if(v&&v.type==='relation'&&k.indexOf('對應')===0){ for(const r of (v.relation||[])) out.push(norm(r.id)); } } return out; };
const allRelTargets = p => { const out=[]; for(const v of Object.values(p.properties||{})){ if(v&&v.type==='relation'){ for(const r of (v.relation||[])) out.push(norm(r.id)); } } return out; };
const XF = ['提案引用','管考引用','項目引用','協作引用','內容引用','明細引用','庫存引用','對象引用','日期引用'];
const dbTitleToXref = t => {
  if(/提案/.test(t)) return '提案引用';
  if(/管考|績效/.test(t)) return '管考引用';
  if(/項目|進度/.test(t)) return '項目引用';
  if(/協作|交接/.test(t)) return '協作引用';
  if(/登記|內容/.test(t)) return '內容引用';
  if(/清單|明細/.test(t)) return '明細引用';
  if(/庫存/.test(t)) return '庫存引用';
  if(/關係|對象/.test(t)) return '對象引用';
  if(/日期|紀錄/.test(t)) return '日期引用';
  return '';
};

const target_id = norm(target.id);
const target_idea = rtOf(target,'執行構想');
const target_name = titleOf(target);
const own_idea = baton.exec_idea || '';

const seen = new Set([target_id, norm(baton.db06_id)]);
const mainAxis = new Set();
for (const id of duiYingRels(target)) { if(!seen.has(id)){ seen.add(id); mainAxis.add(id); } }
const depth2 = [];
for (const id of [...mainAxis].slice(0,12)) {
  const pg = await getPage(id); if(!pg) continue;
  for (const nid of duiYingRels(pg)) { if(!seen.has(nid)){ seen.add(nid); depth2.push(nid); } }
}
for (const id of depth2.slice(0,12)) mainAxis.add(id);
const axisArr = [...mainAxis].slice(0,16);

const tagIds = new Set();
const siblingDB06 = new Set();
for (const t of relIdsOf(target,'對應標籤')) tagIds.add(t);
for (const s of relIdsOf(target,'對應明細')) siblingDB06.add(s);
for (const id of axisArr) {
  const pg = await getPage(id); if(!pg) continue;
  for (const t of relIdsOf(pg,'對應標籤')) tagIds.add(t);
  for (const s of relIdsOf(pg,'對應明細')) siblingDB06.add(s);
}

const sibling_notes = [];
for (const sid of [...siblingDB06].slice(0,12)) {
  if (sid === norm(baton.db06_id)) continue;
  const pg = await getPage(sid); if(!pg) continue;
  const nm=titleOf(pg), idea=rtOf(pg,'執行構想'), note=rtOf(pg,'執行備註');
  if (idea||note) sibling_notes.push(nm+'｜構想:'+idea.slice(0,200)+'｜備註:'+note.slice(0,400));
}

const candIds = new Set();
for (const tid of [...tagIds].slice(0,10)) {
  const tp = await getPage(tid); if(!tp) continue;
  for (const cid of allRelTargets(tp)) { if(!seen.has(cid)&&cid!==target_id) candIds.add(cid); }
}
const rawCand = [];
let skipped = 0;
for (const cid of [...candIds].slice(0,28)) {
  const pg = await getPage(cid); if(!pg){ continue; }
  const nm=titleOf(pg); const sm=rtOf(pg,'簡介摘要'); const an=rtOf(pg,'分析備註');
  const txt = (sm||an||'').slice(0,300);
  if (!nm && !txt) { skipped++; continue; }
  rawCand.push({ id:cid, name:nm||'(未命名)', text:txt, db_id: norm((pg.parent||{}).database_id||'') });
}
const dbCache = {};
for (const c of rawCand) {
  if (!c.db_id) { c.xref=''; continue; }
  if (!(c.db_id in dbCache)) {
    const dbo = await getDB(c.db_id);
    dbCache[c.db_id] = dbo ? dbTitleToXref((dbo.title||[]).map(t=>t.plain_text).join('')) : '';
  }
  c.xref = dbCache[c.db_id];
}
const candidates = rawCand.filter(c=>c.xref);
const noxref = rawCand.length - candidates.length;
const existing_xref = {};
for (const f of XF) existing_xref[f] = relIdsOf(target,f);
return [{ json: { db06_id:baton.db06_id, target_id, target_name, target_idea, own_idea,
  ai_mode:baton.ai_mode, sort_num:baton.sort_num, target_rel:baton.target_rel,
  sibling_notes, candidates, existing_xref, axis_count:axisArr.length, tag_count:tagIds.size,
  cand_count:candidates.length, skipped_count:skipped, noxref_count:noxref } }];

const ctx = $input.first().json;
const sys = '你是 makesense 嗨嗨家族的嗨嗨聯想（織網棒）。職責:從候選池挑出與 target 相關的既有資料,連進 target 的引用欄位。
步驟:(1)先讀 target 的兩個執行構想(整體交辦 + 本棒特別交辦)與兄弟棒次執行備註,萃出 3-5 條「相關性判準」(例:同地點/同主題/同年度/同辦理單位/同系列)。(2)候選池逐筆套判準,命中≥1 條才選,命中 0 條丟掉。寧缺勿濫。
只回合法 JSON:{"criteria":["判準1","判準2",...],"picks":[{"id":"候選id","reason":"命中哪條判準"}]}。picks 最多 50 筆。';
const cand = (ctx.candidates||[]).map(c=>'['+c.id+'] '+c.name+' — '+(c.text||'(無摘要)')).join('
') || '(候選池為空)';
const usr = 'target 名稱：'+ctx.target_name+'

【target 執行構想 — 四九對整篇的交辦】
'+(ctx.target_idea||'(空)')+'

【聯想棒執行構想 — 四九對本棒的特別交辦】
'+(ctx.own_idea||'(空)')+'

【兄弟棒次軌跡】
'+((ctx.sibling_notes||[]).join('
')||'(無)')+'

【候選池 '+(ctx.candidates||[]).length+' 筆】
'+cand+'

先萃 3-5 條判準,再逐筆套判準挑 picks,回 JSON。';
const claude_body = JSON.stringify({ model:'claude-haiku-4-5-20251001', max_tokens:4096, system:sys, messages:[{role:'user',content:usr}] });
return [{ json: { ...ctx, claude_body } }];

const resp = $input.first().json;
const ctx = $('Download PDF + build body').first().json;
const text = resp.content?.[0]?.text || '';
const usage = resp.usage || {};
let parsed; try { const m=text.match(/\{[\s\S]*\}/); parsed=m?JSON.parse(m[0]):{criteria:[],picks:[]}; } catch(e){ parsed={criteria:[],picks:[]}; }
const criteria = Array.isArray(parsed.criteria)?parsed.criteria:[];
const picks = Array.isArray(parsed.picks)?parsed.picks:[];
const id2xref = {}; const valid = new Set();
for (const c of (ctx.candidates||[])) { id2xref[c.id]=c.xref; valid.add(c.id); }
let pickIds = [...new Set(picks.map(p=>(p.id||'').toString().replace(/-/g,'')).filter(id=>valid.has(id)))];
if (pickIds.length > 50) pickIds = pickIds.slice(0,50);
const byField = {};
for (const pid of pickIds) { const f=id2xref[pid]; if(!f) continue; (byField[f]=byField[f]||[]).push(pid); }
const existing = ctx.existing_xref || {};
const patch_properties = {}; const fieldCounts = []; let newTotal = 0;
for (const f of Object.keys(byField)) {
  const ex = existing[f] || [];
  const merged = [...new Set(ex.concat(byField[f]))];
  const added = merged.length - ex.length;
  newTotal += added;
  patch_properties[f] = { relation: merged.map(id=>({id})) };
  fieldCounts.push(f+' +'+added);
}
const it = parseInt(usage.input_tokens||0), ot = parseInt(usage.output_tokens||0);
const cost = ((it*0.8 + ot*4)/1000000*32).toFixed(2);
const usage_line = '進='+it+' 出='+ot+' 成本NT'+cost;
const d = new Date(); const tw = new Date(d.getTime()+8*3600*1000);
const ts = tw.getUTCFullYear()+'-'+String(tw.getUTCMonth()+1).padStart(2,'0')+'-'+String(tw.getUTCDate()).padStart(2,'0')+' '+String(tw.getUTCHours()).padStart(2,'0')+':'+String(tw.getUTCMinutes()).padStart(2,'0');
let note = '── '+ts+' 聯想 ──\n工作對象：'+ctx.target_name+'\n相關性判準：'+(criteria.join('；')||'(未萃出)')+'\n織網結果：候選 '+ctx.cand_count+' 筆,篩選通過新增 '+newTotal+' 筆 X引用 ['+(fieldCounts.join('、')||'無')+']（主軸 '+ctx.axis_count+' 頁、標籤 '+ctx.tag_count+' 個、無可判讀文字略過 '+ctx.skipped_count+' 筆、無法判定DB略過 '+ctx.noxref_count+' 筆）';
note = note.slice(0,1990);
const sanitize = s => (s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g,' ').replace(/\s+/g,' ').trim().slice(0,600);
return [{ json: { db06_id:ctx.db06_id, db05_id:ctx.target_id, target_id:ctx.target_id, ai_mode:ctx.ai_mode, sort_num:ctx.sort_num, patch_properties, has_writes: Object.keys(patch_properties).length>0, lianxiang_full:note, usage_line, safe_summary:sanitize(note), preview_text:'聯想新增 '+newTotal+' 筆引用', validator_warning:'' } }];

const row = $input.first().json || {};
const pc = $('Parse Claude').first().json;
const auto_mode = row.auto_mode === true;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const base = '關卡B 成果確認
第 ' + (pc.sort_num != null ? pc.sort_num : '?') + ' 棒 (' + pc.ai_mode + ') 已完成。
DB06 頁面 ' + pc.db06_id + '

執行備註:
' + pc.safe_summary + '

' + pc.preview_text + (pc.validator_warning || '') + '
tokens ' + pc.usage_line;
const manual_msg = base + '

按 OK 進下一棒,按 OK ALL 之後全自動。要 redo 重跑請打字 reply。
gateB db06=' + pc.db06_id;
const auto_msg = base + '

[全自動模式] 自動進下一棒,免按。';
return [{ json: { auto_mode, reply_to, flow_id: pc.db05_id, db05_id: pc.db05_id, db06_id: pc.db06_id, sort_num: pc.sort_num, ai_mode: pc.ai_mode, manual_msg, auto_msg, cb_ok: 'B1:' + pc.db06_id, cb_all: 'BA:' + pc.db06_id } }];

